  return join(runRootV2, "ast-bench-v2", shape, agentId, `repeat-${repeat}`, lane);
}

export function runManifestPathV2(cell) {
  return join(runDirV2(cell), "run-manifest.json");
}

export function sha256(path) {
  return createHash("sha256").update(readFileSync(path)).digest("hex");
}

export function source(path) {
  return {
    path,
    exists: existsSync(path),
    bytes: existsSync(path) ? readFileSync(path).byteLength : 0,
    sha256: existsSync(path) ? sha256(path) : ""
  };
}

export function hashExisting(paths) {
  return paths.filter((path) => existsSync(path)).map((path) => ({
    path,
    sha256: sha256(path)
  }));
}

export function listFiles(root) {
  if (!existsSync(root)) return [];
  const out = [];
  walk(root);
  return out;

  function walk(path) {
    const stat = statSync(path);
    if (stat.isDirectory()) {
      for (const entry of readdirSync(path).sort()) walk(join(path, entry));
      return;
    }
    out.push(path);
  }
}

export function readRunManifests(suite) {
  const manifests = [];
  for (const task of listTasks(suite)) {
    for (const agent of suite.agents) {
      for (let repeat = 1; repeat <= suite.repeatsPerCell; repeat += 1) {
        for (const lane of suite.lanes) {
          const path = runManifestPath({
            suiteId: suite.suiteId,
            taskId: task.id,
            agentId: agent.id,
            lane: lane.id,
            repeat
          });
          if (existsSync(path)) manifests.push(readJson(path));
        }
      }
    }
  }
  return manifests;
}

export function readRunManifestsV2(suiteV2) {
  const manifests = [];
  for (const shape of suiteV2.shapes) {
    for (const agent of suiteV2.agents) {
      for (let repeat = 1; repeat <= suiteV2.repeatsPerCell; repeat += 1) {
        for (const lane of suiteV2.lanes) {
          const path = runManifestPathV2({ shape, agentId: agent.id, lane: lane.id, repeat });
          if (existsSync(path)) manifests.push(readJson(path));
        }
      }
    }
  }
  return manifests;
}

export function median(values) {
  const sorted = values.filter((value) => Number.isFinite(value)).sort((a, b) => a - b);
  if (!sorted.length) return 0;
  const mid = Math.floor(sorted.length / 2);
  if (sorted.length % 2) return sorted[mid];
  return (sorted[mid - 1] + sorted[mid]) / 2;
}

export function percentile(values, pct) {
  const sorted = values.filter((value) => Number.isFinite(value)).sort((a, b) => a - b);
  if (!sorted.length) return 0;
  const index = Math.min(sorted.length - 1, Math.max(0, Math.ceil((pct / 100) * sorted.length) - 1));
  return sorted[index];
}

export function iqr(values) {
  return percentile(values, 75) - percentile(values, 25);
}

export function formatNumber(value) {
  return new Intl.NumberFormat("en-US").format(Math.round(Number(value) || 0));
}

export function formatMoney(value) {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
    maximumFractionDigits: value < 10 ? 2 : 0
  }).format(Number(value) || 0);
}

export function formatMoneyShort(value) {
  const amount = Number(value) || 0;
  if (amount >= 1_000_000) return `$${Math.round(amount / 100000) / 10}M`;
  if (amount >= 1000) return `$${Math.round(amount / 100) / 10}k`;
  return formatMoney(amount);
}

