    const topOwner = owners[0] || "";
    const nextStep = qualifies
      ? `${topOwner} recovery review by 16:00`
      : "Continue standard monitoring.";

    await Promise.all([
      db.collection("workflow_state").deleteMany({}),
      db.collection("owner_tasks").deleteMany({}),
      db.collection("customer_messages").deleteMany({}),
      db.collection("audit_events").deleteMany({}),
    ]);

    await db.collection("workflow_state").insertOne({
      account_id: account._id,
      status,
      next_step: nextStep,
      risk_summary: riskSummary,
      created_at: nowDate,
    });

    if (owners.length > 0) {
      const dueAt = new Date(nowDate);
      dueAt.setHours(16, 0, 0, 0);
      await db.collection("owner_tasks").insertMany(
        owners.map((owner) => ({
          account_id: account._id,
          owner_group: owner,
          title: `${owner} recovery review for ${account.name}`,
          due_at: dueAt,
          status: "open",
        }))
      );
    }

    const customerMessage = qualifies
      ? `We have identified ${activeSignalList.length} areas requiring immediate attention for your account. Our team has assigned dedicated recovery owners to coordinate resolution across each risk area. We will keep you updated with progress and next steps throughout this process.`
      : `Your account is under standard monitoring. No escalation is required at this time.`;

    await db.collection("customer_messages").insertOne({
      account_id: account._id,
      body: customerMessage,
      created_at: nowDate,
    });

    await db.collection("audit_events").insertOne({
      account_id: account._id,
      event: "rescue_workflow_executed",
      detail: status,
      customer_visible: true,
      created_at: nowDate,
    });
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run()
    .then(() => console.log("workflow done"))
    .catch((e) => {
      console.error(e);
      process.exit(1);
    });
}
